module JC_counter(
    input clk,
    input rst_n,
    output [63:0] Q
);

reg [63:0] q_reg;

always @(posedge clk or negedge rst_n) begin
    if (!rst_n) begin
        q_reg <= 64'b0000000000000000_0000000000000000_0000000000000000_0000000000000000_0000000000000000_0000000000000000_0000000000000000_0000000000000000;
    end
    else begin
        q_reg[63:1] <= q_reg[62:0];
        q_reg[0] <= ~q_reg[63];
    end
end

assign Q = q_reg;

endmodule
